[{"filename": "analyze_car.py", "description": "Main analysis script — DTC code or symptoms in, structured JSON diagnosis out", "content": "#!/usr/bin/env python3
"""
The Grease Cutter — AI-powered car diagnostic & repair cost analyzer.

Takes an OBD diagnostic trouble code (DTC) or a plain-English symptom description
and returns a structured JSON report: diagnosis, severity, likely causes, DIY vs shop
cost breakdown, red flags to watch for, and The Grease Cutter's cold clinical take.

Usage:
    python analyze_car.py "P0301"
    python analyze_car.py "car shaking when accelerating, check engine light on"
    python analyze_car.py "P0420" --vehicle "2018 Honda Civic 1.5T"

Requires: ANTHROPIC_API_KEY environment variable.
"""

import os
import sys
import json
import anthropic


def analyze_car_problem(input_text: str, vehicle_info: str = "") -> dict:
    """Analyze a car problem from a DTC code or symptom description."""
    api_key = os.environ.get("ANTHROPIC_API_KEY")
    if not api_key:
        return {"error": "ANTHROPIC_API_KEY not set"}

    client = anthropic.Anthropic(api_key=api_key)

    vehicle_context = f"\nVehicle: {vehicle_info}" if vehicle_info else ""

    system_prompt = """You are The Grease Cutter — a cold, clinical automotive combat operative who sees through every shop trick in the $300 billion auto repair industry. You know exactly what's wrong, what it actually costs, and what mechanics say to inflate the bill.

Your job: take a diagnostic trouble code (DTC) or symptom description and produce a brutally honest, structured diagnosis that arms the car owner with everything they need to avoid getting ripped off.

You are NOT a replacement for a professional mechanic for safety-critical repairs. You ARE the scanner they don't want you to have.

IMPORTANT: Return ONLY valid JSON. No markdown, no code fences, no commentary outside the JSON."""

    user_prompt = f"""Analyze this car problem and return a JSON object with these exact fields:

INPUT: {input_text}{vehicle_context}

Return this exact JSON structure:
{{
  "input_parsed": {{
    "type": "dtc_code" or "symptom_description",
    "code": "P0301" (if DTC, else null),
    "symptoms_detected": ["list of symptoms extracted"]
  }},
  "diagnosis": {{
    "plain_english": "One-sentence explanation a non-mechanic would understand",
    "technical_detail": "What's actually happening mechanically/electrically",
    "affected_system": "Engine/Transmission/Brakes/Electrical/Exhaust/Suspension/etc"
  }},
  "severity": {{
    "score": 1-10,
    "safe_to_drive": true/false,
    "urgency": "Fix immediately / Fix this week / Fix when convenient / Monitor",
    "what_happens_if_ignored": "Plain-English consequence of ignoring this"
  }},
  "likely_causes": [
    {{
      "cause": "Most likely cause",
      "probability": "High/Medium/Low",
      "explanation": "Why this is likely"
    }}
  ],
  "repair_estimate": {{
    "diy": {{
      "difficulty": 1-10,
      "parts_cost_range": "$X - $Y",
      "time_estimate": "X hours",
      "tools_needed": ["list"],
      "can_a_beginner_do_this": true/false
    }},
    "independent_shop": {{
      "parts_cost_range": "$X - $Y",
      "labor_hours": X.X,
      "labor_rate_range": "$90 - $130/hr typical",
      "total_estimate_range": "$X - $Y"
    }},
    "dealership": {{
      "parts_cost_range": "$X - $Y (OEM)",
      "labor_hours": X.X,
      "labor_rate_range": "$130 - $250/hr typical",
      "total_estimate_range": "$X - $Y"
    }},
    "savings_by_going_independent": "$X - $Y saved vs dealer"
  }},
  "red_flags": [
    "If they tell you [X], they're upselling — the real issue is [Y]",
    "Watch for [common scam tactic related to this repair]"
  ],
  "what_to_say_at_the_shop": [
    "Ask: [specific question that shows you know what's going on]",
    "Say: [phrase that prevents upselling]"
  ],
  "grease_cutter_take": "One paragraph of cold, clinical Durden-energy commentary on this specific repair situation — what the industry doesn't want you to know about THIS problem"
}}

Be specific with dollar amounts based on current US market rates. When in doubt, give ranges. Always include the dealership vs independent comparison — that's where the money is."""

    message = client.messages.create(
        model="claude-sonnet-4-20250514",
        max_tokens=2000,
        messages=[{"role": "user", "content": user_prompt}],
        system=system_prompt,
    )

    response_text = message.content[0].text.strip()

    # Try to parse as JSON
    try:
        result = json.loads(response_text)
    except json.JSONDecodeError:
        # Try to extract JSON from response
        start = response_text.find("{")
        end = response_text.rfind("}") + 1
        if start >= 0 and end > start:
            try:
                result = json.loads(response_text[start:end])
            except json.JSONDecodeError:
                result = {"raw_response": response_text, "error": "Could not parse JSON"}
        else:
            result = {"raw_response": response_text, "error": "No JSON found in response"}

    return result


def main():
    if len(sys.argv) < 2:
        print("Usage: python analyze_car.py <DTC code or symptoms> [--vehicle <year make model>]")
        print('Example: python analyze_car.py "P0301"')
        print('Example: python analyze_car.py "car shaking, check engine light" --vehicle "2019 Toyota Camry"')
        sys.exit(1)

    input_text = sys.argv[1]
    vehicle_info = ""

    if "--vehicle" in sys.argv:
        idx = sys.argv.index("--vehicle")
        if idx + 1 < len(sys.argv):
            vehicle_info = sys.argv[idx + 1]

    result = analyze_car_problem(input_text, vehicle_info)
    print(json.dumps(result, indent=2))


if __name__ == "__main__":
    main()
"}]
